#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Register a model in MLflow Model Registry
 *
 * This example demonstrates:
 * - Working with model registry (Note: Full Model Registry V2 support coming soon)
 * - Model versioning concepts
 * - Model lifecycle management
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 *
 * Usage:
 *   npx ts-node examples/workspace/ml/register-model.ts
 *
 * Note: This example demonstrates the concept. Full Model Registry operations
 * require Unity Catalog Models API which is available through the REST API.
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    console.log("Model Registry Example");
    console.log(
        "Note: Full Model Registry V2 (Unity Catalog Models) support coming soon"
    );

    try {
        console.log("\nModel Registry Concepts:");
        console.log("- Registered Models: Named ML model");
        console.log("- Model Versions: Specific iterations of a model");
        console.log("- Model Stages: None, Staging, Production, Archived");
        console.log(
            "- Model Aliases: Named pointers to versions (champion, challenger)"
        );

        console.log("\nFor now, use the Databricks REST API directly:");
        console.log("- POST /api/2.0/mlflow/registered-models/create");
        console.log("- GET /api/2.0/mlflow/registered-models/get");
        console.log("- POST /api/2.0/mlflow/model-versions/create");
        console.log("- POST /api/2.0/mlflow/model-versions/transition-stage");

        console.log("\nOr use Unity Catalog Models:");
        console.log("- List models: client.registeredModels.list()");
        console.log("- Get model: client.registeredModels.get()");

        // Example: List Unity Catalog models (if available)
        try {
            console.log("\nAttempting to list Unity Catalog models...");
            const models = [];
            for await (const model of client.registeredModels.list({
                catalog_name: "main",
                schema_name: "default",
            })) {
                models.push({
                    "Name": model.name,
                    "Full Name": model.full_name,
                });
                if (models.length >= 5) {
                    break;
                }
            }

            if (models.length > 0) {
                console.table(models);
            } else {
                console.log("  No models found in main.default");
            }
        } catch (error: any) {
            console.log(`  Could not list models: ${error.message || error}`);
        }

        console.log("\n✓ Model Registry example complete");
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
